import math


def simulator(x: float, fidelity: str) -> dict[str, object]:
    if not -3.0 <= x <= 3.0:
        raise ValueError("x is outside the design domain")
    cost = {"low": 1.0, "high": 12.0}[fidelity]
    if x > 2.4:
        return {"status": "failed", "fidelity": fidelity, "cost": cost, "value": None}
    if fidelity == "high" and x < -2.2:
        return {"status": "censored", "fidelity": fidelity, "cost": cost, "value": None}
    high = 0.16 * (x - 1.7) ** 2 + 0.45 * math.sin(2.2 * x) + 0.12 * math.sin(5.3 * x)
    bias = 0.18 * math.sin(1.4 * x + 0.3) if fidelity == "low" else 0.0
    deterministic_noise = 0.03 * math.sin(7.0 * x) if fidelity == "low" else 0.01 * math.sin(7.0 * x)
    return {"status": "ok", "fidelity": fidelity, "cost": cost, "value": high + bias + deterministic_noise}


print(simulator(0.5, "low"))
print(simulator(0.5, "high"))

from ortools.sat.python import cp_model

staff, days, shifts = range(4), range(3), range(2)
required = {(d, h): 1 for d in days for h in shifts}
preference = {(s, d, h): (s + d + h) % 2 for s in staff for d in days for h in shifts}
model = cp_model.CpModel()
x = {(s, d, h): model.new_bool_var(f"x_{s}_{d}_{h}") for s in staff for d in days for h in shifts}
for d in days:
    for h in shifts:
        model.add(sum(x[s, d, h] for s in staff) >= required[d, h])
for s in staff:
    for d in days:
        model.add(sum(x[s, d, h] for h in shifts) <= 1)
    for d in range(2):
        model.add(x[s, d, 1] + x[s, d + 1, 0] <= 1)
model.add(x[3, 0, 1] == 0)
workloads = [sum(x[s, d, h] for d in days for h in shifts) for s in staff]
max_load, min_load = model.new_int_var(0, 3, "max_load"), model.new_int_var(0, 3, "min_load")
model.add_max_equality(max_load, workloads)
model.add_min_equality(min_load, workloads)
model.maximize(10 * sum(preference[s, d, h] * x[s, d, h] for s in staff for d in days for h in shifts) - (max_load - min_load))
solver = cp_model.CpSolver()
status = solver.solve(model)
print(solver.status_name(status), [[solver.value(x[s, d, h]) for h in shifts] for s in staff for d in days])

import numpy as np

def loss_proxy(q: np.ndarray) -> float:
    r, curvature, shift = q
    return float((r - 1.45) ** 2 + 0.4 * curvature**2 + 0.2 * shift**2 + 0.05 * (r - 1.0) ** 2)

q = np.array([1.15, 0.0, 0.0])
print(loss_proxy(q))

import nevergrad as ng

space = ng.p.Dict(
    u1=ng.p.Scalar(lower=0.0, upper=1.0),
    u2=ng.p.Scalar(lower=0.0, upper=1.0),
    mode=ng.p.Choice([0, 1]),
)

def evaluate(u1, u2, mode):
    if u1 + u2 < 0.25:
        raise RuntimeError("simulation did not converge")
    return (u1 - 0.65) ** 2 + (u2 - 0.35) ** 2 + 0.08 * mode

optimizer = ng.optimizers.NGOpt(parametrization=space, budget=40)
for _ in range(40):
    candidate = optimizer.ask()
    try:
        value = evaluate(**candidate.value)
    except RuntimeError:
        value = float("inf")
    optimizer.tell(candidate, value)
print(optimizer.provide_recommendation().value)

import numpy as np
from scipy.optimize import root

def equations(x):
    return np.array([x[0] ** 2 + x[1] - 1.0, x[0] + x[1] ** 2 - 1.0])

def jacobian(x):
    return np.array([[2.0 * x[0], 1.0], [1.0, 2.0 * x[1]]])

result = root(equations, x0=np.array([0.7, 0.7]), jac=jacobian)
print(result.x, np.linalg.norm(equations(result.x)), result.success)
